import React, { useEffect, useState } from "react";

export default function Profile() {
  const [user, setUser] = useState(null);
  const token = localStorage.getItem("token");

  useEffect(() => {
    async function fetchProfile() {
      try {
        const res = await fetch("http://localhost:5000/api/profile", {
          headers: { Authorization: `Bearer ${token}` },
        });
        const data = await res.json();
        setUser(data.user || null);
      } catch (e) {
        setUser(null);
      }
    }
    if (token) fetchProfile();
  }, [token]);

  // Action list config for maintainable rendering
  const sections = [
    {
      items: [{ label: "Change Language" }, { label: "Theme" }],
    },
    {
      items: [{ label: "Settings" }, { label: "Fields" }],
    },
    {
      items: [{ label: "Storage" }, { label: "Export" }],
    },
    {
      items: [{ label: "Log Out", type: "danger" }],
    },
    {
      items: [
        { label: "Support Portal" },
        { label: "User Manual" },
        { label: "Contact" },
      ],
    },
  ];

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#e2e5f3",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        paddingTop: 22,
        fontFamily: "Inter",
        boxSizing: "border-box",
      }}
    >
      {/* Top Bar */}
      <div
        style={{
          width: "100%",
          maxWidth: 370,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 10,
          padding: "0 10px",
        }}
      >
        <span style={{ fontSize: 22, fontWeight: 500 }}>&larr;</span>
        <span style={{ fontWeight: 600, fontSize: 18 }}>Profile</span>
        <div>
          <span style={{ fontSize: 19, marginRight: 8 }}>&#128269;</span>
          <span style={{ fontSize: 19 }}>&#128276;</span>
        </div>
      </div>
      {/* Profile Card */}
      <div
        style={{
          background: "#fff",
          borderRadius: 16,
          maxWidth: 330,
          width: "100%",
          margin: "10px auto 23px auto",
          padding: "18px 0 18px 16px",
          display: "flex",
          alignItems: "center",
          boxShadow: "0 1px 10px #e5e9f570",
          gap: 18,
        }}
      >
        <img
          src={
            user?.profilePic || "https://randomuser.me/api/portraits/men/1.jpg"
          }
          alt={user?.name || "User"}
          style={{
            width: 45,
            height: 45,
            borderRadius: "50%",
            objectFit: "cover",
            marginRight: 18,
          }}
        />
        <div>
          <div style={{ fontWeight: 600, fontSize: 16, color: "#232743" }}>
            {user?.name || "Monica Bhalla"}
          </div>
          <div style={{ color: "#a3aabd", fontSize: 13 }}>
            {user?.type || "Customer Account"}
          </div>
        </div>
      </div>

      {/* Section Groups */}
      <div style={{ maxWidth: 330, width: "100%" }}>
        {sections.map((section, idx) => (
          <div
            key={idx}
            style={{
              background: "#f6f7fb",
              borderRadius: 13,
              marginBottom: 13,
              padding: section.items.length === 1 ? "10px 0" : "3px 0",
              boxShadow: "0 1px 8px #e5e9f530",
            }}
          >
            {section.items.map((item, j) => (
              <div
                key={item.label}
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  padding: item.type === "danger" ? "15px 19px" : "13px 19px",
                  color: item.type === "danger" ? "#e84d4f" : "#232743",
                  fontWeight: item.type === "danger" ? 700 : 500,
                  fontSize: 15,
                  borderBottom:
                    j < section.items.length - 1 ? "1px solid #e3e7f7" : "none",
                  cursor: "pointer",
                }}
              >
                <span>{item.label}</span>
                <span style={{ color: "#8990ae", fontSize: 17 }}>&#8250;</span>
              </div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}
